query:
UPDATE calculos
SET mesRef = CONCAT(LPAD(SUBSTRING(mesRef, 1, LENGTH(mesRef)-2), 2, '0'), '/20', SUBSTRING(mesRef, LENGTH(mesRef)-1))
WHERE mesRef REGEXP '^[0-9]{3,4}$' AND mesRef NOT LIKE '%/%';

